SELECT AVG(total_spent) AS average_order_amount
FROM (
    SELECT o.contact_id, SUM(o.total_amount) AS total_spent
    FROM orders o
    GROUP BY o.contact_id
) AS contact_totals;

SELECT quantity 
FROM order_items 
WHERE order_item_id = 1;

SELECT COUNT(*)
FROM record_changes
WHERE changedon = '2023-01-02 13:00:00';
